course_modules.content:
:::lesson-cards
[
  {
    "type": "mission_brief",
    "title": "The Evidence Hierarchy",
    "label": "Core Foundation",
    "visualKey": "time-compression-board",
    "body": "Think of a timeframe as a **Filter for Weight**. A 1-minute candle records the tiny wiggles of the market. A Daily candle hides those wiggles and only records the big, heavy decisions. \n\n**The Rule**: More time inside a candle = More Evidence Weight.",
    "context": {
      "keyTerms": [
        {
          "term": "Evidence Weight",
          "definition": "How much 'truth' a candle holds based on the time it represents."
        },
        {
          "term": "Institutional Weight",
          "definition": "The massive capital commitment of banks and funds."
        }
      ],
      "whyThisMatters": "Retail traders lose because they treat a 1-minute 'wiggle' with the same respect as a Daily 'move.' This is like trying to predict the weather by looking at a single raindrop.",
      "realLifeExample": "A Daily candle is a full book; a 1-minute candle is just a single sentence. You can't understand the story if you only read one sentence at a time.",
      "commonMistake": "Thinking that a fast move on a small timeframe 'proves' the market has changed direction.",
      "quickNote": "Don't trust the wiggles. Trust the weight."
    }
  },
  {
    "type": "visual_intro",
    "title": "Narrative Layers",
    "label": "Structural Mapping",
    "visualKey": "timeframe-comparison-windows",
    "body": "The market is a stack of stories (Narratives) happening at once. A lower timeframe might look urgent, but it is often just a small detail inside a much larger institutional story. You must identify which layer is currently 'The Boss.'",
    "context": {
      "keyTerms": [
        {
          "term": "The Narrative",
          "definition": "The big, slow story told by the Higher Timeframes (HTF)."
        },
        {
          "term": "The Detail",
          "definition": "The fast, noisy story told by the Lower Timeframes (LTF)."
        }
      ],
      "whyThisMatters": "To avoid traps, you must know if a move is a 'New Story' or just a 'Detail' within an old one. This stops you from buying right before a Higher Timeframe wall hits you.",
      "realLifeExample": "A city bus might turn left to avoid a pothole (LTF), but the route is still moving North (HTF). Don't let the turn fool you.",
      "commonMistake": "Getting 'Zoomed In' and forgetting where the big price walls are.",
      "quickNote": "The bigger the timeframe, the bigger the boss."
    }
  },
  {
    "type": "visual_intro",
    "title": "The Weight of the Record",
    "label": "Quantitative Logic",
    "visualKey": "timeframe-weight-ladder",
    "body": "Not all evidence is equal. We use a **Weight Ladder** to prioritize what we see. Higher timeframes have 'Structural Gravity'—they are harder to move and easier to trust because they represent a consensus of the biggest players.",
    "context": {
      "keyTerms": [
        {
          "term": "Structural Gravity",
          "definition": "The tendency of price to obey big-timeframe levels over small-timeframe ones."
        },
        {
          "term": "Consensus",
          "definition": "When the majority of market participants agree on a direction."
        }
      ],
      "whyThisMatters": "A $750 student doesn't 'guess'; they stack evidence. A Daily rejection is 100x more powerful than a 5-minute rejection. We prioritize our reading from the top down.",
      "realLifeExample": "Trying to stop a moving train (HTF) vs. stopping a rolling bicycle (LTF). The weight defines the difficulty.",
      "commonMistake": "Ignoring the 'Gravity' of the higher timeframe and trying to trade against it.",
      "quickNote": "Always check the weight before you take a side."
    }
  },
  {
    "type": "visual_intro",
    "title": "Signature vs. Noise",
    "label": "Participant Roles",
    "visualKey": "htf-ltf-roles",
    "body": "To read like a pro, you must separate the **Whales** from the **Minnows**.\n\n* **The Signature (HTF)**: The clear footprints of Banks and Sovereign Funds. They move with strategy.\n* **The Noise (LTF)**: The frantic wiggles of Algorithms and Retail Emotions. They move with panic.",
    "context": {
      "keyTerms": [
        {
          "term": "Institutional Signature",
          "definition": "High-weight evidence left by massive capital flows."
        },
        {
          "term": "Retail Noise",
          "definition": "Unstable movement driven by speculation and high-frequency bots."
        }
      ],
      "whyThisMatters": "Institutions use the 'Noise' to hide their true 'Signature.' If you only watch the noise, you are the exit liquidity for the whales.",
      "realLifeExample": "The Compass (Signature) shows you where the island is. The Microscope (Noise) only shows you the dust on the deck of the ship.",
      "commonMistake": "Watching the 1-minute chart and thinking you are seeing the 'Truth' of the market.",
      "quickNote": "Follow the Signature, ignore the Noise."
    }
  },
  {
    "type": "visual_intro",
    "title": "Resolving Conflict",
    "label": "Evidence Auditing",
    "visualKey": "timeframe-conflict-board",
    "body": "What if the layers disagree? If the 5-minute is pushing up but the 4-hour is hitting a wall, the evidence is **Mixed**. A professional does not flip a coin; they label the market 'Unclear' and wait for the layers to align.",
    "context": {
      "keyTerms": [
        {
          "term": "Mixed Evidence",
          "definition": "When your timeframe layers are telling different stories."
        },
        {
          "term": "Wait for Alignment",
          "definition": "Staying out of the market until the layers agree."
        }
      ],
      "whyThisMatters": "Most losses happen during 'Conflict.' By simply identifying conflict and walking away, you instantly become more profitable than 90% of retail traders.",
      "realLifeExample": "A red light (HTF) and a green light (LTF) at the same intersection. The disciplined driver waits for clarity.",
      "commonMistake": "Forcing a decision when the data is clearly messy.",
      "quickNote": "If the layers fight, you stay out."
    }
  },
  {
    "type": "visual_intro",
    "title": "Timeframe Personality: Trend vs. Range",
    "label": "Structural Mapping",
    "visualKey": "timeframe-personality-board",
    "body": "A timeframe is not just a clock; it's a personality. A Higher Timeframe might be in a calm, disciplined trend, while a Lower Timeframe is in a messy, chaotic range. You must identify the personality of each layer before you trust the evidence.",
    "context": {
      "keyTerms": [
        {
          "term": "Timeframe Personality",
          "definition": "The current behavioral state (Trend/Range/Chaos) of a specific layer."
        },
        {
          "term": "HTF Personality",
          "definition": "The dominant macro direction or state."
        },
        {
          "term": "LTF Personality",
          "definition": "The local behavior, which may be noisy or ranging even inside a trend."
        }
      ],
      "whyThisMatters": "Most traders assume that if the 4H is trending, the 5m must be trending too. This assumption leads to buying 'Messy' movement. We only act when the personality supports the mission.",
      "realLifeExample": "A big ship moving steadily across the ocean (HTF Trend). On the deck, people are running back and forth in a chaotic game (LTF Range). The ship's route is clear, but the deck is messy.",
      "commonMistake": "Ignoring the messy personality of the lower timeframe just because the higher timeframe is trending.",
      "quickNote": "Identify the personality before you trust the move."
    }
  },
  {
    "type": "visual_intro",
    "title": "The Evidence Audit Checklist",
    "label": "Process Control",
    "visualKey": "evidence-audit-checklist-board",
    "body": "A professional doesn't trust their gut; they trust their process. Before forming a conclusion, you must audit each layer of the hierarchy. If you can't verify the location, alignment, and behavior, the evidence quality is too low for a clean reading.",
    "context": {
      "keyTerms": [
        {
          "term": "Evidence Audit",
          "definition": "A manual verification of every layer in the hierarchy."
        },
        {
          "term": "Verification",
          "definition": "Confirming that a specific piece of evidence meets clinical standards."
        },
        {
          "term": "Clinical Standards",
          "definition": "Fixed rules for what counts as 'Clean' evidence."
        }
      ],
      "whyThisMatters": "The checklist removes the emotional urge to trade and replaces it with logical discipline. If you can't check every box, you don't have a reading.",
      "realLifeExample": "A surgeon before an operation. They check the patient's identity and the equipment. They don't skip the checklist just because they feel 'confident.'",
      "commonMistake": "Skipping the audit because the move 'looks' obvious.",
      "quickNote": "The audit must be clinical before the reading is clean."
    }
  },
  {
    "type": "visual_intro",
    "title": "The Evidence Stack Workflow",
    "label": "Strategic Audit",
    "visualKey": "top-down-reading-workflow",
    "body": "Professional reading always moves from the **Outside In**. We audit the Narrative first, define the Structure second, and only use the Detail to refine our timing. If the layers don't stack, the quality is too low to act.",
    "context": {
      "keyTerms": [
        {
          "term": "Outside-In Audit",
          "definition": "Starting from the Daily/4H and zooming in to the 5m."
        },
        {
          "term": "Evidence Stack",
          "definition": "A collection of facts from multiple layers that all point the same way."
        }
      ],
      "whyThisMatters": "Most gamblers start on the 1-minute chart and 'hallucinate' a reason to buy. The $750 student starts on the Daily and 'verifies' a reason to act.",
      "realLifeExample": "Checking the weather (HTF) before you check the engine (LTF) of your plane. Both matter, but one defines the mission.",
      "commonMistake": "Starting at the bottom and hoping the top agrees.",
      "quickNote": "Narrative first. Detail last."
    }
  },
  {
    "type": "practice",
    "title": "Final Audit Practice",
    "label": "Strategic Decision",
    "visualKey": "timeframe-decision-scenario",
    "body": "TEST CASE: You see an aggressive 5-minute push (Detail) moving directly into a major 4-hour resistance wall (Narrative). \n\n**What is the disciplined reading?**",
    "taskData": {
      "type": "choice_block",
      "question": "What is the disciplined reading?",
      "options": [
        {
          "id": "A",
          "text": "The 5m push is very strong; the market has turned bullish.",
          "isCorrect": false,
          "feedback": "Wrong: You are letting 'Noise' overrule 'Signature.' One 5m move rarely breaks a 4H wall on the first try."
        },
        {
          "id": "B",
          "text": "The 4H wall is old; the 5m move is the 'new' truth.",
          "isCorrect": false,
          "feedback": "Wrong: 'Newer' doesn't mean 'Heavier.' The 4H wall represents thousands of times more capital than the 5m push."
        },
        {
          "id": "C",
          "text": "The evidence is mixed. I will stay 'Unclear' and wait for alignment.",
          "isCorrect": true,
          "feedback": "Correct: You have identified 'Conflict.' A professional waits for the high-weight layer and the low-weight layer to point in the same direction."
        },
        {
          "id": "D",
          "text": "I'll take a small trade to see if it breaks through.",
          "isCorrect": false,
          "feedback": "Wrong: This is 'Curiosity Trading,' not 'Evidence Auditing.' We only act when the stack is aligned."
        }
      ]
    },
    "context": {
      "whyThisMatters": "Learning to say 'I don't know' in a messy market is the most expensive skill in trading.",
      "quickNote": "Don't bet on the Noise against the Narrative."
    }
  },
  {
    "type": "summary",
    "title": "Module Debrief: The Hierarchy of Evidence",
    "label": "Module Recap",
    "visualKey": "timeframe-debrief-board",
    "body": "You have successfully completed the **Institutional Reset**. You no longer see charts as 'just bars'—you see them as a stack of Narrative layers. You now have the filter to separate real market movement from retail noise.\n\n### Your New Competencies:\n\n* [x] Identify **Whale Signatures** vs. **Retail Noise**\n* [x] Audit the market from the **Outside-In**\n* [x] Resolve **Mixed Evidence** by staying patient\n* [x] Respect **Structural Gravity**\n\n**Next**: We map the market's skeleton: **Basic Structure**.",
    "context": {
      "whyThisMatters": "This 'Evidence Filter' is what separates you from the gambling crowd. You are now reading the same data as the banks.",
      "quickNote": "You are now an Evidence Auditor."
    }
  }
]
:::

course_modules.forex_adaptation:
:::lesson-cards
[
  {
    "type": "visual_intro",
    "title": "Forex Timeframes Are Session Records",
    "visualKey": "forex-session-timeframe-board",
    "label": "Forex Foundation",
    "body": "A 15-minute candle records 15 minutes of activity. But in Forex, those 15 minutes are not equal across the day. A candle formed during quiet Asia, London open, New York overlap, or major news does not carry the same environment. \n\n**The Formula**: timeframe + session = reading environment",
    "context": {
      "keyTerms": [
        {
          "term": "Forex Session",
          "definition": "A major trading window such as Asia, London, or New York."
        },
        {
          "term": "Session Context",
          "definition": "The market environment created by the active trading region and participation level."
        },
        {
          "term": "Reading Environment",
          "definition": "The condition surrounding the candle: quiet, active, volatile, or mixed."
        },
        {
          "term": "Session Record",
          "definition": "A candle understood through both its timeframe and the session that created it."
        }
      ],
      "whyThisMatters": "If a learner reads only the candle duration, they miss the market environment behind the candle. Forex movement changes across the trading day.",
      "realLifeExample": "A 15-minute EUR/USD candle during late Asia may be slow and narrow. A 15-minute EUR/USD candle after London opens may form inside a much more active environment.",
      "commonMistake": "Reading Forex candles as if every hour of the day has the same quality.",
      "quickNote": "In Forex, timeframe tells you how long. Session tells you what kind of market."
    }
  },
  {
    "type": "visual_intro",
    "title": "The Forex Trading Day Has Rhythms",
    "visualKey": "forex-trading-rhythm-board",
    "label": "Session Rhythm",
    "body": "Forex is a 24-hour market, but participation is not equal across all hours. The market has rhythm: Asia, London, New York, and overlaps. Some periods are quiet, some are active, and some are unstable because of economic releases. \n\n**The Rule**: Know the environment you are reading.",
    "context": {
      "keyTerms": [
        {
          "term": "Asia Session",
          "definition": "A major trading window often associated with quieter movement in many major pairs."
        },
        {
          "term": "London Session",
          "definition": "A major trading window often associated with stronger Forex participation."
        },
        {
          "term": "New York Session",
          "definition": "A major trading window that can bring continuation, reversal, or news-driven movement."
        },
        {
          "term": "Session Rhythm",
          "definition": "The changing activity pattern across the Forex trading day."
        },
        {
          "term": "Participation",
          "definition": "The amount of market activity and involvement behind price movement."
        }
      ],
      "whyThisMatters": "A learner who ignores session rhythm may treat quiet movement, active movement, and event-driven movement as the same kind of evidence.",
      "realLifeExample": "A pair may stay tight during Asia, expand during London, and react sharply during New York data. The timeframe stayed the same, but the environment changed.",
      "commonMistake": "Thinking the market is equally active just because Forex is open.",
      "quickNote": "Forex is open for long hours, but activity comes in waves."
    }
  },
  {
    "type": "visual_intro",
    "title": "Session Handoffs and Overlaps",
    "visualKey": "forex-handoff-overlap-board",
    "label": "Liquidity Windows",
    "body": "Session handoffs and overlaps can change how a timeframe behaves. A candle formed during an overlap may carry more participation than one formed during a quiet period. But activity alone is not enough. The learner still needs structure, context, and close-location review.",
    "context": {
      "keyTerms": [
        {
          "term": "Session Handoff",
          "definition": "A transition period where one major trading region becomes less active and another becomes more active."
        },
        {
          "term": "Overlap",
          "definition": "A time window where two major sessions are active at the same time."
        },
        {
          "term": "Liquidity Window",
          "definition": "A period where market participation may be stronger."
        },
        {
          "term": "Activity Spike",
          "definition": "A sudden increase in price movement or participation."
        },
        {
          "term": "Clean Movement",
          "definition": "Movement that is easier to read because it has structure and follow-through."
        }
      ],
      "whyThisMatters": "Many Forex learners get excited when movement increases. But stronger activity can create useful evidence or unstable movement depending on context.",
      "realLifeExample": "London opens and EUR/USD starts moving faster. A trained learner does not call direction immediately. They check whether the move is breaking structure or only reacting to fresh activity.",
      "commonMistake": "Assuming every session overlap move is automatically clean.",
      "quickNote": "Overlap can increase activity. It does not guarantee clarity."
    }
  },
  {
    "type": "visual_intro",
    "title": "Same Candle, Different Session Meaning",
    "visualKey": "forex-candle-weight-board",
    "label": "Candle Quality",
    "body": "A Forex candle gains meaning from the environment that produced it. The same candle shape can be weak, useful, or unstable depending on session activity, liquidity, and news pressure. Candle shape alone is not enough.",
    "context": {
      "keyTerms": [
        {
          "term": "Evidence Weight",
          "definition": "The relative importance of a candle after considering timeframe and context."
        },
        {
          "term": "Candle Quality",
          "definition": "How useful a candle is as market evidence."
        },
        {
          "term": "Thin Movement",
          "definition": "Movement formed in a weaker or less active environment."
        },
        {
          "term": "Active Session Candle",
          "definition": "A candle formed during stronger market participation."
        },
        {
          "term": "Unstable Candle",
          "definition": "A candle formed in conditions where movement may be fast but not clean."
        }
      ],
      "whyThisMatters": "Forex learners often memorize candle shapes. This card teaches them to judge the quality of the candle, not just the appearance.",
      "realLifeExample": "A strong-looking candle during London may matter more than the same shape printed during a quiet period. But if the candle forms during news, it may be unstable instead of clean.",
      "commonMistake": "Thinking the same candle shape has the same meaning in every trading hour.",
      "quickNote": "The candle shape is only part of the reading. The session gives it weight."
    }
  },
  {
    "type": "visual_intro",
    "title": "News Windows Distort Timeframe Reading",
    "visualKey": "forex-news-distortion-board",
    "label": "Event Pressure",
    "body": "A Forex candle formed during a major news window may record real market reaction, but it can also include unstable movement, spread changes, violent wicks, or fast repricing. The disciplined learner does not treat a news candle as clean until structure and follow-through appear.",
    "context": {
      "keyTerms": [
        {
          "term": "News Window",
          "definition": "The time around major economic releases or central bank events."
        },
        {
          "term": "Repricing",
          "definition": "A fast adjustment in price after new information enters the market."
        },
        {
          "term": "Spread Expansion",
          "definition": "A widening difference between bid and ask during unstable conditions."
        },
        {
          "term": "Event Volatility",
          "definition": "Fast movement caused by scheduled or unexpected events."
        },
        {
          "term": "Follow-Through",
          "definition": "What price does after the event candle closes."
        }
      ],
      "whyThisMatters": "Many Forex learners mistake fast news movement for high-quality evidence. Speed can create drama without clarity.",
      "realLifeExample": "GBP/USD prints a huge candle after economic data. A rushed learner sees direction. A trained learner waits to see whether the next candles confirm the move or reject it.",
      "commonMistake": "Treating every large news candle as a clean directional reading.",
      "quickNote": "News can make a candle loud before it becomes clear."
    }
  },
  {
    "type": "visual_intro",
    "title": "Higher-Timeframe Location in Forex",
    "visualKey": "forex-location-context-board",
    "label": "Pair Location",
    "body": "In Forex, a lower-timeframe move can be active and still incomplete. The higher timeframe shows where the pair is located in the broader structure. A trained learner checks location before trusting local movement.",
    "context": {
      "keyTerms": [
        {
          "term": "Higher-Timeframe Location",
          "definition": "Where price sits in the broader chart structure."
        },
        {
          "term": "Major Area",
          "definition": "A zone that has mattered previously in the market."
        },
        {
          "term": "Local Movement",
          "definition": "Shorter-term movement inside a broader context."
        },
        {
          "term": "Support / Resistance Area",
          "definition": "A price zone where the market has previously reacted."
        },
        {
          "term": "Incomplete Reading",
          "definition": "A reading that needs more context before becoming strong."
        }
      ],
      "whyThisMatters": "Without location, learners overreact to local movement and miss the broader structure.",
      "realLifeExample": "EUR/USD rallies on 15m, but the 4H chart shows price pressing into a previous resistance zone. The rally is real, but the broader context still matters.",
      "commonMistake": "Trusting a small-timeframe move without checking where the pair is on the larger chart.",
      "quickNote": "In Forex, location comes before reaction."
    }
  },
  {
    "type": "visual_intro",
    "title": "Lower-Timeframe Session Behavior",
    "visualKey": "forex-behavior-lens-board",
    "label": "Local Behavior",
    "body": "Lower timeframes are useful when they explain behavior inside a known context. They become dangerous when the learner treats them as the whole market. In Forex, lower-timeframe charts should refine the reading, not replace the broader reading.",
    "context": {
      "keyTerms": [
        {
          "term": "Local Behavior",
          "definition": "Short-term price action inside a broader context."
        },
        {
          "term": "Behavior Lens",
          "definition": "Using a smaller timeframe to observe how price is reacting now."
        },
        {
          "term": "Refinement",
          "definition": "Adding detail to an existing reading."
        },
        {
          "term": "Noise",
          "definition": "Movement that feels important but does not improve the broader reading."
        },
        {
          "term": "Reaction",
          "definition": "How price behaves near an important area or condition."
        }
      ],
      "whyThisMatters": "Lower timeframes are where many learners become emotional. This card teaches them how to use detail without becoming controlled by it.",
      "realLifeExample": "The 1H chart shows price near a zone. The 5m chart helps observe whether price is rejecting, slowing, or pushing through that zone.",
      "commonMistake": "Using lower timeframes to create the main opinion instead of refining an existing one.",
      "quickNote": "Lower timeframes should explain behavior, not create blind confidence."
    }
  },
  {
    "type": "visual_intro",
    "title": "Multi-Timeframe Forex Reading Process",
    "visualKey": "forex-reading-stack-board",
    "label": "Forex Workflow",
    "body": "Professional Forex reading moves through a structured audit. You start with the broader building (HTF Location), then check the environment (Session Timing & Events), and only then use the local detail (Structure & Behavior) to refine the reading.",
    "context": {
      "keyTerms": [
        {
          "term": "Forex Top-Down Reading",
          "definition": "A process for reading from broader context into session behavior and local detail."
        },
        {
          "term": "HTF Location",
          "definition": "Identifying the broader chart structure before local analysis."
        },
        {
          "term": "Session Timing",
          "definition": "Audit of participation quality based on the current trading hour."
        },
        {
          "term": "Event Pressure",
          "definition": "Checking for news-driven distortion or upcoming catalysts."
        },
        {
          "term": "Reading Quality",
          "definition": "Whether the evidence is clear, mixed, or unclear."
        }
      ],
      "whyThisMatters": "Forex is fast and fragmented. A fixed process slows the learner down and improves the quality of the evidence they accept.",
      "realLifeExample": "EUR/USD pushes on 15m. A trained learner checks 4H location, London participation, and upcoming CPI data before trusting the move.",
      "commonMistake": "Starting from the fastest chart and letting session speed control the reading.",
      "quickNote": "Read Forex from session into behavior, not from speed into emotion."
    }
  },
  {
    "type": "practice",
    "title": "Forex Timeframe Conflict Drill",
    "visualKey": "forex-timeframe-drill",
    "label": "Practice Drill",
    "body": "This drill tests whether you can separate active session movement from full timeframe alignment. A Forex move can be real and still incomplete. The trained learner does not call the reading clean until broader context, working structure, and session behavior support each other.",
    "taskData": {
      "type": "choice_block",
      "question": "GBP/USD shows a strong 15-minute bullish push during London session. The 1-hour chart is still inside a range, and the 4-hour chart shows price near a previous resistance area. \n\nWhat is the disciplined Forex reading?",
      "options": [
        {
          "id": "A",
          "text": "The 15-minute candle is strong, so the pair is clearly bullish.",
          "isCorrect": false,
          "feedback": "Not correct. A strong lower-timeframe candle does not automatically define the whole pair. You still need higher-timeframe and session context."
        },
        {
          "id": "B",
          "text": "London activity means the move must continue.",
          "isCorrect": false,
          "feedback": "Not correct. London activity can increase participation, but it does not guarantee continuation."
        },
        {
          "id": "C",
          "text": "The lower-timeframe push is active, but higher-timeframe context is not fully aligned. This is a mixed reading until structure confirms.",
          "isCorrect": true,
          "feedback": "Correct. The 15-minute move is active and worth observing, but the 1-hour range and 4-hour resistance reduce clarity. This is a mixed reading until the pair shows stronger alignment across timeframe and structure."
        },
        {
          "id": "D",
          "text": "The higher timeframe does not matter because the 15-minute chart is more recent.",
          "isCorrect": false,
          "feedback": "Not correct. Newer does not always mean more important. Lower-timeframe movement must be read inside broader context."
        }
      ]
    },
    "context": {
      "keyTerms": [
        {
          "term": "Mixed Reading",
          "definition": "A condition where some evidence supports the move but other layers reduce clarity."
        },
        {
          "term": "Alignment",
          "definition": "When multiple timeframes support the same reading."
        },
        {
          "term": "Active but Incomplete",
          "definition": "Movement that is worth observing but not strong enough for a clean conclusion."
        },
        {
          "term": "Confirmation",
          "definition": "Additional structure or behavior that strengthens the reading."
        }
      ],
      "whyThisMatters": "Forex often produces active lower-timeframe moves during major sessions. The learner’s job is not to chase activity. The learner’s job is to judge alignment.",
      "realLifeExample": "GBP/USD pushes upward during London, but the 4H chart still shows resistance. A rushed learner calls it bullish. A trained learner marks it as active but not fully confirmed.",
      "commonMistake": "Confusing active session movement with full multi-timeframe alignment.",
      "quickNote": "In Forex, active is not the same as aligned."
    }
  },
  {
    "type": "summary",
    "title": "Forex Debrief: Time, Session, Structure",
    "visualKey": "forex-roadway-debrief",
    "label": "Roadway Debrief",
    "body": "You are no longer reading Forex candles as isolated shapes. You now understand that every candle belongs to a timeframe, every timeframe forms inside a session, and every session move must be checked against broader structure. This is how Forex reading becomes disciplined instead of reactive.",
    "context": {
      "keyTerms": [
        {
          "term": "Session Context",
          "definition": "The trading environment behind the candle."
        },
        {
          "term": "Timeframe Alignment",
          "definition": "When multiple timeframes support the same reading."
        },
        {
          "term": "Reading Quality",
          "definition": "Whether the evidence is clear, mixed, or unclear."
        },
        {
          "term": "Pair Location",
          "definition": "Where the currency pair sits in broader structure."
        },
        {
          "term": "Top-Down Forex Reading",
          "definition": "Reading from broader context into session behavior and local detail."
        }
      ],
      "whyThisMatters": "Forex becomes much easier to misread when the learner ignores time, session, and structure. This roadway gives a repeatable process.",
      "realLifeExample": "Two learners see the same 15m candle. One reacts to the candle. The trained learner asks which session created it, where the pair is on 4H, and whether the move is aligned.",
      "commonMistake": "Leaving with session names but no reading process.",
      "quickNote": "Forex candles are read through time, session, and structure together."
    }
  }
]
:::

course_modules.crypto_adaptation:
:::lesson-cards
[
  {
    "type": "visual_intro",
    "title": "Crypto Timeframes Run 24/7",
    "visualKey": "crypto-continuous-market-board",
    "label": "Crypto Foundation",
    "body": "A crypto timeframe is a candle duration inside a continuous market. The chart may keep printing candles all day and all weekend, but the quality of those candles can change with activity, liquidity, venue behavior, BTC context, and event pressure.",
    "context": {
      "keyTerms": [
        {
          "term": "24/7 Market",
          "definition": "A market that continues trading across days, nights, weekends, and holidays."
        },
        {
          "term": "Crypto Timeframe",
          "definition": "The amount of time represented by one crypto candle."
        },
        {
          "term": "Market Condition",
          "definition": "The environment behind the candle, such as active, quiet, thin, volatile, or event-driven."
        },
        {
          "term": "Candle Quality",
          "definition": "How useful a candle is as evidence after considering the condition that created it."
        },
        {
          "term": "Continuous Trading",
          "definition": "A market structure where candles keep forming without traditional daily closure."
        }
      ],
      "whyThisMatters": "Crypto learners can become overconfident because there is always movement. But movement does not always mean clean evidence. A candle formed during a thin or unstable period may be weaker than it looks.",
      "realLifeExample": "BTC may form a sharp 15-minute candle late at night with low participation, then form another 15-minute candle during a high-activity period. Same timeframe, different quality of evidence.",
      "commonMistake": "Thinking crypto candles are equally meaningful just because the chart is always active.",
      "quickNote": "Crypto never sleeps, but candle quality still changes."
    }
  },
  {
    "type": "visual_intro",
    "title": "The Crypto Day Has Activity Cycles",
    "visualKey": "crypto-activity-cycle-board",
    "label": "Activity Rhythm",
    "body": "Crypto does not follow the same session structure as Forex, but it still has activity rhythms. Some windows attract more participation, some are quieter, and some become unstable because of events, funding pressure, or broader market attention.",
    "context": {
      "keyTerms": [
        {
          "term": "Activity Cycle",
          "definition": "A repeated change in market participation across time."
        },
        {
          "term": "Participation",
          "definition": "The amount of activity behind price movement."
        },
        {
          "term": "Quiet Window",
          "definition": "A period where movement may be thinner or less reliable."
        },
        {
          "term": "Active Window",
          "definition": "A period where participation and volume may be stronger."
        },
        {
          "term": "Funding Time",
          "definition": "A scheduled moment in perpetual markets that can influence positioning behavior."
        },
        {
          "term": "Event Window",
          "definition": "A period around important announcements, listings, unlocks, or market-wide catalysts."
        }
      ],
      "whyThisMatters": "A learner who ignores activity rhythm may treat every candle as equal. Crypto movement can look similar on the chart but come from very different levels of participation.",
      "realLifeExample": "A token may barely move for hours, then suddenly expand when US market attention increases or when a major crypto event hits the market.",
      "commonMistake": "Assuming “24/7” means every hour has the same market quality.",
      "quickNote": "Crypto is always open, but participation is not always equal."
    }
  },
  {
    "type": "visual_intro",
    "title": "Same Candle, Different Market Condition",
    "visualKey": "crypto-candle-quality-board",
    "label": "Candle Quality",
    "body": "A crypto candle gains meaning from the condition that created it. The same candle shape can be useful, weak, exaggerated, or unstable depending on liquidity, venue activity, spot support, perpetual pressure, and event context.",
    "context": {
      "keyTerms": [
        {
          "term": "Candle Condition",
          "definition": "The market environment that created the candle."
        },
        {
          "term": "Spot Participation",
          "definition": "Actual buying or selling of the asset in spot markets."
        },
        {
          "term": "Thin Liquidity",
          "definition": "A condition where price can move sharply because available orders are limited."
        },
        {
          "term": "Perp-Driven Move",
          "definition": "Movement strongly influenced by perpetual contract pressure."
        },
        {
          "term": "Event Spike",
          "definition": "A fast candle caused by a sudden catalyst or market reaction."
        },
        {
          "term": "Evidence Quality",
          "definition": "How reliable a candle is as part of a market reading."
